// src/TravelHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function TravelHistory({ employee }) {
  const navigate = useNavigate();
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee?.empld) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const res = await fetch(
        `${apiBase}/travel-expenses?empld=${encodeURIComponent(employee.empld)}`
      );
      const data = await res.json();
      setTravelExpenses(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Travel history fetch error:", err);
      setTravelExpenses([]);
    }
  };

  const filtered = travelExpenses.filter((t) => {
    const d = t.travel_date?.split?.("T")?.[0] || t.travel_date;
    if (startDate && d < startDate) return false;
    if (endDate && d > endDate) return false;
    return true;
  });

  const handleDownloadPDF = () => window.print();

  const deleteTravel = async (id) => {
    if (!window.confirm("Delete this travel record?")) return;
    try {
      const res = await fetch(`${apiBase}/travel-expenses/${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (!data.success) return alert(data.message);
      setTravelExpenses((prev) => prev.filter((t) => t.id !== id));
    } catch {
      alert("Delete error");
    }
  };

  const editTravel = async (row) => {
    const newDate =
      window.prompt("Travel Date:", row.travel_date?.split?.("T")?.[0]) ||
      row.travel_date;
    const newPurpose = window.prompt("Purpose:", row.purpose) || row.purpose;
    const newFrom =
      window.prompt("From:", row.location_from) || row.location_from;
    const newTo = window.prompt("To:", row.location_to) || row.location_to;
    const newAmount = window.prompt("Amount:", row.amount) || row.amount;

    try {
      const res = await fetch(`${apiBase}/travel-expenses/${row.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          travel_date: newDate,
          purpose: newPurpose,
          location_from: newFrom,
          location_to: newTo,
          amount: newAmount,
          mode_of_travel: row.mode_of_travel || "",
        }),
      });

      const data = await res.json();
      if (!data.success) return alert("Update failed");

      setTravelExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                travel_date: newDate,
                purpose: newPurpose,
                location_from: newFrom,
                location_to: newTo,
                amount: newAmount,
              }
            : t
        )
      );
    } catch {
      alert("Update error");
    }
  };

  if (!employee)
    return (
      <div style={centerScreen}>
        <div>Please login again.</div>
      </div>
    );

  return (
    <div style={outer}>
      <div style={card}>
        {/* HEADER */}
        <div style={headerRow}>
          <button style={backBtn} onClick={() => navigate("/history")}>
            ⬅ Back
          </button>
          <h2 style={title}>Travel Expense History</h2>
        </div>

        <p style={empInfo}>
          {employee.name} • {employee.empld}
        </p>

        {/* FILTERS */}
        <div style={filterBar}>
          <div style={filterBlock}>
            <span>From</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>
          <div style={filterBlock}>
            <span>To</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>
          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear
          </button>
        </div>

        {/* TABLE */}
        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Amount</th>
              <th>From</th>
              <th>To</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((t) => (
              <tr key={t.id}>
                <td>{t.travel_date?.split?.("T")?.[0]}</td>
                <td>{t.purpose}</td>
                <td>₹{t.amount}</td>
                <td>{t.location_from}</td>
                <td>{t.location_to}</td>
                <td>
                  <button style={editBtn} onClick={() => editTravel(t)}>
                    Edit
                  </button>
                  <button style={delBtn} onClick={() => deleteTravel(t.id)}>
                    Delete
                  </button>
                </td>
              </tr>
            ))}

            {filtered.length === 0 && (
              <tr>
                <td colSpan="6" style={noData}>
                  No records found.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* PDF BUTTON */}
        <div style={pdfRow}>
          <button style={pdfBtn} onClick={handleDownloadPDF}>
            Download PDF
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------- STYLES ----------
const outer = {
  minHeight: "100vh",
  background: lightGreen,
  padding: 20,
  fontFamily: "Segoe UI",
};

const centerScreen = {
  ...outer,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#fff",
  padding: 20,
  borderRadius: 16,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };

const backBtn = {
  background: "none",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const title = { color: green, margin: 0 };
const empInfo = { fontSize: 13, marginTop: 6, color: "#555" };

const filterBar = {
  display: "flex",
  gap: 10,
  flexWrap: "wrap",
  padding: 10,
  margin: "14px 0",
  background: "#f9fff9",
  borderRadius: 10,
  border: "1px solid #eaf8f0",
};

const filterBlock = { display: "flex", flexDirection: "column", fontSize: 12 };

const filterInput = {
  padding: 5,
  borderRadius: 6,
  border: "1px solid #ccc",
};

const clearBtn = {
  padding: "5px 12px",
  borderRadius: 8,
  border: "1px solid #ccc",
  background: "#fff",
  cursor: "pointer",
};

const table = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};

const editBtn = {
  padding: "3px 8px",
  marginRight: 6,
  borderRadius: 6,
  border: `1px solid ${green}`,
  background: "#fff",
  color: green,
  cursor: "pointer",
};

const delBtn = {
  padding: "3px 8px",
  borderRadius: 6,
  border: "1px solid #c62828",
  background: "#fff",
  color: "#c62828",
  cursor: "pointer",
};

const pdfRow = {
  display: "flex",
  justifyContent: "flex-start",
  marginTop: 20,
};

const pdfBtn = {
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  fontSize: 13,
  cursor: "pointer",
};

const noData = {
  textAlign: "center",
  padding: 10,
};
